  Component,
  Vue,
} from "nuxt-property-decorator"
import ImgRow from "~/components/img-row.vue";

@Component({
  components: {ImgRow},
  head: () => ({
    title: "Рисовач"
  })
})
export default class art extends Vue {
  material: string = "";
  theme: string = "";

  showTagGen = false;
  showTags = false;
  tagsStr = "";

  generateTags() {
    this.showTags = true;

    let tags = ["#art", "#арт", "#drawing", "#рисунок"];

    switch (this.material) {
      case "oil":
        tags.push("#oilpainting", "#масло");
        break;
      case "watercolor":
        tags.push("#watercolor", "#акварель");
        break;
      case "pencil":
        tags.push("#pencildrawing", "#карандаш");
        break;
      case "ink":
        tags.push("#ink", "#тушь");
        break;
      case "pen":
        tags.push("#pen", "#ручка");
        break;
      case "coal":
        tags.push("#coal", "#уголь");
        break;
      case "sanguine":
        tags.push("#sanguine", "#сангина");
        break;
      default:
        break;
    }

    switch (this.theme) {
      case "portrait":
        tags.push("#portrait", "#портрет");
        break;
      case "stilllife":
        tags.push("#stilllife", "#натюрморт");
        break;
      case "landscape":
        tags.push("#landscape", "#пейзаж");
        break;
      case "sketch":
        tags.push("#sketching", "#скетч");
        break;
      default:
        break;
    }

    this.tagsStr = tags.join(" ");
  }

  showYobnemImg = false;
}
